    "infrastructure",
    "deployment",
    "pipeline",
    "orchestrat",
];

/// Keywords indicating low complexity.
const LOW_COMPLEXITY_KEYWORDS: &[&str] = &[
    "fix",
    "typo",
    "rename",
    "update",
    "tweak",
    "minor",
    "simple",
    "small",
