/// Calculate the priority component score.
///
/// Per the specification:
/// - P0 = 40 points
/// - P1 = 32 points
/// - P2 = 24 points
/// - P3 = 16 points
/// - P4+ = 8 points
fn calculate_priority_score(&self, priority: u8) -> u32 {
    match priority {
        0 => 40, // P0 Critical
        1 => 32, // P1 High
        2 => 24, // P2 Medium
        3 => 16, // P3 Low
        _ => 8,  // P4+ Backlog
    }
}

