//! Claude API provider using direct HTTP requests.
//!
//! This module provides [`ClaudeApiProvider`] which makes direct API calls to
//! Anthropic's Claude API using the reqwest HTTP client.
//!
//! ## Error Recovery
//!
//! The provider implements automatic retry logic for transient errors:
//! - Network timeouts: Retried with exponential backoff
//! - 5xx server errors: Retried up to 3 times
//! - Rate limits: Wait time extracted from response header
//!
//! ## Example
//!
//! ```no_run
//! use forge_chat::{claude_api::ClaudeApiProvider, config::ClaudeApiConfig, context::DashboardContext, provider::ChatProvider};
//!
//! # async fn example() -> anyhow::Result<()> {
//! let config = ClaudeApiConfig::default();
//! let provider = ClaudeApiProvider::from_config(config)?;
//!
//! let context = DashboardContext::default();
//! let tools = vec![];
//! let response = provider.process("Hello!", &context, &tools).await?;
//! println!("{}", response.text);
//! # Ok(())
//! # }
//! ```

use ::async_trait::async_trait;
use tokio::time::Duration;
use tracing::{debug, warn, info};

use crate::claude_api_types::{
    ApiMessage, ApiRequest, ApiResponse, ApiTool, ApiUsage, ContentBlock,
    StreamEvent, StreamChunk, ContentBlockDelta,
};
use crate::config::ClaudeApiConfig;
use crate::context::DashboardContext;
use crate::error::{ChatError, Result};
use crate::provider::{FinishReason, ProviderTool, TokenUsage};
use crate::tools::ToolCall;

/// Maximum retries for transient network errors.
const MAX_RETRIES: u32 = 3;

/// Initial delay for exponential backoff (in milliseconds).
const INITIAL_RETRY_DELAY_MS: u64 = 500;

/// Maximum delay for retries.
const MAX_RETRY_DELAY: Duration = Duration::from_secs(30);

/// Claude API provider using direct HTTP requests.
///
/// This provider uses the reqwest client to make direct API calls to
/// Anthropic's Claude API.
pub struct ClaudeApiProvider {
    config: ClaudeApiConfig,
    client: reqwest::Client,
    api_key: String,
    base_url: String,
}

impl ClaudeApiProvider {
    /// Create a new Claude API provider from config.
    pub fn from_config(config: ClaudeApiConfig) -> Result<Self> {
        let api_key = std::env::var(&config.api_key_env).map_err(|_| {
            ChatError::ConfigError(format!(
                "{} environment variable not set",
                config.api_key_env
            ))
        })?;

        let client = reqwest::Client::builder()
            .timeout(Duration::from_secs(config.timeout_secs))
            .connect_timeout(Duration::from_secs(10))
            .build()
            .map_err(|e| ChatError::ConfigError(format!("Failed to create HTTP client: {}", e)))?;

        let base_url = config.api_base_url.clone();

        Ok(Self {
            config,
            client,
            api_key,
            base_url,
        })
    }

    /// Create a provider with a custom API key.
    pub fn with_api_key(mut config: ClaudeApiConfig, api_key: impl Into<String>) -> Result<Self> {
        let api_key = api_key.into();
        let client = reqwest::Client::builder()
            .timeout(Duration::from_secs(config.timeout_secs))
            .connect_timeout(Duration::from_secs(10))
            .build()
            .map_err(|e| ChatError::ConfigError(format!("Failed to create HTTP client: {}", e)))?;

        let base_url = config.api_base_url.clone();

        // Override the api_key_env to indicate we're using a custom key
        config.api_key_env = "<custom>".to_string();

        Ok(Self {
            config,
            client,
            api_key,
            base_url,
        })
    }

    /// Build the API request from prompt, context, and tools.
    fn build_request(
        &self,
        prompt: &str,
        context: &DashboardContext,
        tools: &[ProviderTool],
    ) -> ApiRequest {
        // Build the enhanced prompt with context
        let enhanced_prompt = format!(
            "{}\n\nCurrent dashboard state:\n{}",
            prompt,
            context.to_summary()
        );

        ApiRequest {
            model: self.config.model.clone(),
            max_tokens: self.config.max_tokens,
            temperature: Some(self.config.temperature),
            system: SYSTEM_PROMPT.to_string(),
            messages: vec![ApiMessage {
                role: "user".to_string(),
                content: enhanced_prompt,
            }],
            tools: tools
                .iter()
                .map(|t| ApiTool {
                    name: t.name.clone(),
                    description: t.description.clone(),
                    input_schema: t.input_schema.clone(),
                })
                .collect(),
        }
    }

    /// Send the API request with automatic retry for transient errors.
    ///
    /// This method implements exponential backoff retry logic for:
    /// - Network timeouts
    /// - Connection failures
    /// - 5xx server errors
    /// - Rate limit (429) responses (with retry-after header)
    async fn send_request_with_retry(&self, request: &ApiRequest) -> Result<ApiResponse> {
        let mut attempt = 0;
        let mut delay = Duration::from_millis(INITIAL_RETRY_DELAY_MS);

        loop {
            attempt += 1;

            match self.send_request_once(request).await {
                Ok(response) => {
                    if attempt > 1 {
                        info!(
                            attempt,
                            "API request succeeded after retry"
                        );
                    }
                    return Ok(response);
                }
                Err(ref e) if e.is_retryable() && attempt <= MAX_RETRIES => {
                    // For rate limit errors, use the retry-after duration
                    let wait_duration = if let Some(retry_after_secs) = e.retry_after_secs() {
                        let retry_after = Duration::from_secs(retry_after_secs);

                        // Telemetry: Log rate limit event
                        info!(
                            event = "api_rate_limited",
                            attempt,
                            retry_after_secs,
                            model = %self.config.model,
                            "API rate limit encountered (429), waiting for retry-after duration"
                        );

                        retry_after
                    } else {
                        delay
                    };

                    warn!(
                        event = "api_retry",
                        attempt,
                        max_retries = MAX_RETRIES,
                        delay_ms = wait_duration.as_millis(),
                        error = %e,
                        is_rate_limit = e.is_rate_limit(),
                        "API request failed, retrying with backoff"
                    );

                    tokio::time::sleep(wait_duration).await;

                    // Exponential backoff with cap (only for non-rate-limit errors)
                    if e.retry_after_secs().is_none() {
                        delay = std::cmp::min(delay * 2, MAX_RETRY_DELAY);
                    }
                }
                Err(e) => {
                    if attempt > 1 {
                        warn!(
                            attempt,
                            error = %e,
                            "API request failed after all retries"
                        );
                    }
                    return Err(e);
                }
            }
        }
    }

    /// Send a single API request (without retry logic).
    async fn send_request_once(&self, request: &ApiRequest) -> Result<ApiResponse> {
        debug!("Sending API request to {}", self.base_url);

        let response = self
            .client
            .post(format!("{}/v1/messages", self.base_url))
            .header("x-api-key", &self.api_key)
            .header("anthropic-version", "2023-06-01")
            .header("content-type", "application/json")
            .json(request)
            .send()
            .await
            .map_err(|e| {
                Self::classify_network_error(e, &self.base_url, self.config.timeout_secs)
            })?;

        let status = response.status();

        if !status.is_success() {
            let status_code = status.as_u16();

            // Extract retry-after header if present (convert to owned String)
            let retry_after = response
                .headers()
                .get("retry-after")
                .and_then(|v| v.to_str().ok())
                .map(|s| s.to_string());

            let body = response.text().await.unwrap_or_default();

            // Check if this is a retryable error
            if matches!(status_code, 429 | 500 | 502 | 503 | 504) {
                return Err(ChatError::from_http_response(status_code, &body, retry_after.as_deref()));
            }

            return Err(ChatError::ApiError(format!(
                "API error ({}): {}",
                status_code, body
            )));
        }

        response.json().await.map_err(|e| {
            ChatError::ApiError(format!("Failed to parse API response: {}", e))
        })
    }

    /// Classify a reqwest error into a specific ChatError variant.
    ///
    /// This function provides detailed error classification for better user guidance:
    /// - Timeout errors: Connection or read timeouts
    /// - DNS resolution failures: Cannot resolve hostname
    /// - Network unreachable: No internet connection
    /// - Connection failures: Generic connection issues
    fn classify_network_error(error: reqwest::Error, base_url: &str, timeout_secs: u64) -> ChatError {
        let error_string = error.to_string().to_lowercase();

        // Check for timeout first
        if error.is_timeout() {
            return ChatError::Timeout(
                timeout_secs,
                format!("Request to {} timed out after {}s", base_url, timeout_secs),
            );
        }

        // Check for DNS resolution failures
        // reqwest error messages include "dns error" or "failed to lookup address"
        if error_string.contains("dns")
            || error_string.contains("failed to lookup address")
            || error_string.contains("name or service not known")
            || error_string.contains("nodename nor servname provided")
        {
            // Extract hostname from base_url
            let host = base_url
                .strip_prefix("https://")
                .or_else(|| base_url.strip_prefix("http://"))
                .unwrap_or(base_url)
                .split('/')
                .next()
                .unwrap_or(base_url);

            return ChatError::DnsResolutionFailed {
                host: host.to_string(),
                message: error.to_string(),
            };
        }

        // Check for network unreachable (no internet)
        // Common patterns: "network unreachable", "host unreachable", "no route to host"
        if error_string.contains("network unreachable")
            || error_string.contains("no route to host")
            || error_string.contains("host unreachable")
        {
            return ChatError::NetworkUnreachable(format!(
                "Cannot reach {}. Check your internet connection.",
                base_url
            ));
        }

        // Check for connection failures (refused, reset, etc.)
        if error.is_connect() {
            return ChatError::ConnectionFailed(format!(
                "Could not connect to {}: {}",
                base_url, error
            ));
        }

        // Fallback to generic HTTP error
        ChatError::HttpError(error)
    }

    /// Parse the API response into text and tool calls.
    fn parse_response(api_response: ApiResponse) -> (String, Vec<ToolCall>) {
        let mut text = String::new();
        let mut tool_calls = Vec::new();

        for content in api_response.content {
            match content {
                ContentBlock::Text { text: t } => {
                    text.push_str(&t);
                }
                ContentBlock::ToolUse { id, name, input } => {
                    tool_calls.push(ToolCall {
                        name: name.clone(),
                        parameters: input.clone(),
                        id: Some(id),
                    });
                }
            }
        }

        (text, tool_calls)
    }

    /// Estimate cost based on model and usage.
    fn estimate_cost(&self, usage: &ApiUsage) -> f64 {
        let (input_cost_per_million, output_cost_per_million) =
            if self.config.model.contains("opus") {
                (15.0, 75.0)
            } else if self.config.model.contains("sonnet") {
                (3.0, 15.0)
            } else {
                (0.25, 1.25) // Haiku
            };

        let input_cost = (usage.input_tokens as f64 / 1_000_000.0) * input_cost_per_million;
        let output_cost = (usage.output_tokens as f64 / 1_000_000.0) * output_cost_per_million;

        input_cost + output_cost
    }

    /// Send a streaming API request, returning a stream of chunks.
    ///
    /// This method uses Server-Sent Events (SSE) to stream the response
    /// token by token as it's generated by the API.
    pub async fn process_streaming(
        &self,
        prompt: &str,
        context: &DashboardContext,
        tools: &[ProviderTool],
    ) -> Result<impl futures_util::Stream<Item = StreamChunk>> {
        let request = self.build_request(prompt, context, tools);

        debug!("Sending streaming API request to {}", self.base_url);

        let response = self
            .client
            .post(format!("{}/v1/messages", self.base_url))
            .header("x-api-key", &self.api_key)
            .header("anthropic-version", "2023-06-01")
            .header("content-type", "application/json")
            .json(&request)
            .query(&[("stream", "true")])
            .send()
            .await
            .map_err(|e| {
                Self::classify_network_error(e, &self.base_url, self.config.timeout_secs)
            })?;

        let status = response.status();

        if !status.is_success() {
            let status_code = status.as_u16();

            // Extract retry-after header if present (convert to owned String)
            let retry_after = response
                .headers()
                .get("retry-after")
                .and_then(|v| v.to_str().ok())
                .map(|s| s.to_string());

            let body = response.text().await.unwrap_or_default();

            // Use from_http_response for proper error classification
            if matches!(status_code, 429 | 500 | 502 | 503 | 504) {
                return Err(ChatError::from_http_response(status_code, &body, retry_after.as_deref()));
            }

            return Err(ChatError::ApiError(format!(
                "API error ({}): {}",
                status_code, body
            )));
        }

        // Convert the byte stream to a stream of StreamChunk
        Ok(async_stream::stream! {
            let mut buffer = Vec::new();
            let mut output_tokens: u32 = 0;

            use futures_util::StreamExt;

            // Use reqwest's streaming capability
            let mut stream = response.bytes_stream();

            while let Some(chunk_result) = stream.next().await {
                match chunk_result {
                    Ok(bytes) => {
                        buffer.extend_from_slice(&bytes);

                        // Process all complete SSE events from the buffer
                        while let Some(event_end) = buffer.iter().position(|&b| b == b'\n') {
                            let event_bytes = buffer.drain(..=event_end).collect::<Vec<_>>();
                            // Don't drain again - we already drained up to and including the newline

                            let event_str = String::from_utf8_lossy(&event_bytes);

                            // Parse SSE event
                            if let Some(json_str) = event_str.strip_prefix("data: ") {
                                if json_str.trim() == "[DONE]" {
                                    // Stream finished
                                    yield StreamChunk {
                                        text: String::new(),
                                        is_done: true,
                                        usage: Some(ApiUsage {
                                            input_tokens: 0,
                                            output_tokens,
                                            cache_read_tokens: Some(0),
                                            cache_creation_tokens: Some(0),
                                        }),
                                        error: None,
                                    };
                                    return;
                                }

                                match serde_json::from_str::<StreamEvent>(json_str) {
                                    Ok(event) => {
                                        match event {
                                            StreamEvent::MessageStart { message } => {
                                                debug!("Streaming message started: {}", message.id);
                                                // We'll get input_tokens here if available in the API response
                                            }
                                            StreamEvent::ContentBlockStart { .. } => {
                                                // Content block starting
                                            }
                                            StreamEvent::ContentBlockDelta { delta, .. } => {
                                                match delta {
                                                    ContentBlockDelta::TextDelta { text } => {
                                                        yield StreamChunk {
                                                            text,
                                                            is_done: false,
                                                            usage: None,
                                                            error: None,
                                                        };
                                                    }
                                                    ContentBlockDelta::InputJsonDelta { .. } => {
                                                        // Tool call JSON delta - not implemented for streaming display
                                                    }
                                                }
                                            }
                                            StreamEvent::ContentBlockStop { .. } => {
                                                // Content block ended
                                            }
                                            StreamEvent::MessageDelta { usage: delta_usage, .. } => {
                                                if let Some(delta) = delta_usage {
                                                    output_tokens = delta.output_tokens;
                                                }
                                            }
                                            StreamEvent::MessageStop => {
                                                debug!("Streaming message stopped");
                                                yield StreamChunk {
                                                    text: String::new(),
                                                    is_done: true,
                                                    usage: Some(ApiUsage {
                                                        input_tokens: input_tokens.unwrap_or(0),
                                                        output_tokens,
                                                        cache_read_tokens: Some(0),
                                                        cache_creation_tokens: Some(0),
                                                    }),
                                                    error: None,
                                                };
                                            }
                                            StreamEvent::Ping => {
                                                // Keep-alive ping, ignore
                                            }
                                            StreamEvent::Error { error } => {
                                                yield StreamChunk {
                                                    text: String::new(),
                                                    is_done: true,
                                                    usage: None,
                                                    error: Some(error.message),
                                                };
                                                return;
                                            }
                                        }
                                    }
                                    Err(e) => {
                                        // Some events might not match our enum, that's okay
                                        debug!("Failed to parse streaming event: {}, JSON: {}", e, json_str.trim());
                                    }
                                }
                            }
                        }
                    }
                    Err(e) => {
                        let err_msg = format!("Stream error: {}", e);
                        yield StreamChunk {
                            text: String::new(),
                            is_done: true,
                            usage: None,
                            error: Some(err_msg),
                        };
                        return;
                    }
                }
            }

            // If we exit the loop without seeing [DONE], still send a done event
            yield StreamChunk {
                text: String::new(),
                is_done: true,
                usage: Some(ApiUsage {
                    input_tokens: 0,
                    output_tokens,
                    cache_read_tokens: Some(0),
                    cache_creation_tokens: Some(0),
                }),
                error: None,
            };
        })
    }
}

#[async_trait]
impl crate::provider::ChatProvider for ClaudeApiProvider {
    async fn process(
        &self,
        prompt: &str,
        context: &DashboardContext,
        tools: &[ProviderTool],
    ) -> Result<crate::provider::ProviderResponse> {
        let start = std::time::Instant::now();

        // Build and send the request with automatic retry
        let request = self.build_request(prompt, context, tools);
        let api_response = self.send_request_with_retry(&request).await?;

        // Parse the response
        let (text, tool_calls) = Self::parse_response(api_response.clone());

        let duration = start.elapsed().as_millis() as u64;
        let cost = self.estimate_cost(&api_response.usage);

        let finish_reason = if !tool_calls.is_empty() {
            FinishReason::ToolCall
        } else {
            FinishReason::Stop
        };

        let usage = TokenUsage {
            input_tokens: api_response.usage.input_tokens,
            output_tokens: api_response.usage.output_tokens,
            cache_read_tokens: api_response.usage.cache_read_tokens.unwrap_or(0),
            cache_creation_tokens: api_response.usage.cache_creation_tokens.unwrap_or(0),
        };

        Ok(crate::provider::ProviderResponse {
            text,
            tool_calls,
            duration_ms: duration,
            cost_usd: Some(cost),
            finish_reason,
            usage: Some(usage),
        })
    }

    fn name(&self) -> &str {
        "claude-api"
    }

    fn supports_streaming(&self) -> bool {
        true
    }

    fn estimated_cost(&self) -> Option<f64> {
        // Estimate based on max_tokens setting
        let (input_cost, output_cost) = if self.config.model.contains("opus") {
            (15.0, 75.0)
        } else if self.config.model.contains("sonnet") {
            (3.0, 15.0)
        } else {
            (0.25, 1.25)
        };
        // Rough estimate: assume 10k input, max_tokens output
        let estimated_input = 10_000.0;
        let estimated_output = self.config.max_tokens as f64;
        Some(
            (estimated_input / 1_000_000.0) * input_cost
                + (estimated_output / 1_000_000.0) * output_cost,
        )
    }

    fn model(&self) -> &str {
        &self.config.model
    }
}

/// System prompt for the chat agent.
const SYSTEM_PROMPT: &str = r#"You are the conversational interface for a distributed worker control panel called FORGE.

Context:
- The user manages a pool of coding agents (workers) across multiple workspaces
- Workers process "beads" (tasks) using different LLM models (Sonnet, Opus, GLM, etc.)
- The system optimizes costs across subscriptions and pay-per-token APIs
- You have access to real-time dashboard state and can execute commands

Your role:
- Answer questions about worker status, costs, tasks, and subscriptions
- Execute commands safely (confirm destructive operations)
- Provide analysis and recommendations
- Be concise (max 5 sentences unless asked for details)
- Use tables, progress bars, and formatting when helpful
- Explain your reasoning when making recommendations

Response format:
- Use markdown for formatting
- Tables for comparisons
- Status indicators: ✓ (success), ✗ (failure), ◐ (in progress)
- Progress bars: ████▌ 66%
- Keep responses under 10 lines (TUI space is limited)

Safety rules:
- Always confirm before killing workers
- Explain cost implications for model changes
- Warn about context loss when reassigning in-progress tasks
- Rate limit: User can run max 10 commands/minute
"#;

