// ============ Mock Provider ============

/// Mock provider for testing.
///
/// Returns predefined responses without making any external calls.
///
/// # Features
///
/// - Call tracking: records all prompts sent to the provider
/// - Multiple responses: can return different responses for sequential calls
/// - Tool call simulation: can simulate tool calls in responses
/// - Error simulation: can simulate errors for testing error handling
///
/// # Example
///
/// ```no_run
/// use forge_chat::provider::MockProvider;
///
/// let provider = MockProvider::new()
///     .with_response("First response")
///     .and_then_response("Second response")
///     .and_then_error("API error");
///
/// // First call returns "First response"
/// // Second call returns "Second response"
/// // Third call returns an error
/// ```
pub struct MockProvider {
    model: String,
    responses: Arc<Mutex<Vec<MockResponse>>>,
    calls: Arc<Mutex<Vec<MockCall>>>,
    response_delay_ms: u64,
    simulate_error_after: Option<(usize, String)>,
}

/// A mock response that can be returned by the MockProvider.
#[derive(Debug, Clone)]
struct MockResponse {
    text: String,
    tool_calls: Vec<ToolCall>,
    is_error: bool,
    error_message: Option<String>,
}

impl MockResponse {
    fn success(text: impl Into<String>) -> Self {
        Self {
            text: text.into(),
            tool_calls: vec![],
            is_error: false,
            error_message: None,
        }
    }

    fn with_tool_call(mut self, name: impl Into<String>, parameters: serde_json::Value) -> Self {
        self.tool_calls.push(ToolCall {
            name: name.into(),
            parameters,
            id: Some(format!("mock-tool-{}", self.tool_calls.len())),
        });
        self
    }

    fn error(message: impl Into<String>) -> Self {
        Self {
            text: String::new(),
            tool_calls: vec![],
            is_error: true,
            error_message: Some(message.into()),
        }
    }
}

/// Record of a call made to the MockProvider.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MockCall {
    /// The prompt that was sent.
    pub prompt: String,
    /// The tools that were available.
    pub tools_available: usize,
    /// Timestamp of the call.
    #[serde(skip)]
    pub timestamp: chrono::DateTime<chrono::Utc>,
}

impl MockProvider {
    /// Create a new mock provider with default responses.
    pub fn new() -> Self {
        Self::from_config(MockConfig::default())
    }

    /// Create a mock provider from config.
    pub fn from_config(config: MockConfig) -> Self {
        Self {
            model: config.model,
            responses: Arc::new(Mutex::new(vec![MockResponse::success(config.response)])),
            calls: Arc::new(Mutex::new(vec![])),
            response_delay_ms: config.delay_ms,
            simulate_error_after: None,
        }
    }

    /// Set a single response text (replaces all queued responses).
    pub fn with_response(mut self, text: impl Into<String>) -> Self {
        self.responses = Arc::new(Mutex::new(vec![MockResponse::success(text.into())]));
        self
    }

    /// Set multiple responses at once.
    ///
    /// # Example
    ///
    /// ```no_run
    /// # use forge_chat::provider::MockProvider;
    /// let provider = MockProvider::new()
    ///     .with_multiple_responses(["First", "Second", "Third"]);
    /// ```
    pub fn with_multiple_responses<I>(mut self, responses: I) -> Self
    where
        I: IntoIterator,
        I::Item: Into<String>,
    {
        let resp: Vec<MockResponse> = responses
            .into_iter()
            .map(|s| MockResponse::success(s.into()))
            .collect();
        self.responses = Arc::new(Mutex::new(resp));
        self
    }

    /// Add another response to the queue (chains with current responses).
    ///
    /// Note: This method may not work correctly when the provider is already
    /// shared. For reliable multi-response setup, use `with_multiple_responses`.
    pub fn and_then_response(mut self, text: impl Into<String>) -> Self {
        // Clone the Arc first to avoid borrow issues
        let responses_arc = self.responses.clone();
        let mut current = match responses_arc.try_lock() {
            Ok(guard) => guard.clone(),
            Err(_) => {
                // Lock failed, can't chain
                return self;
            }
        };

        current.push(MockResponse::success(text.into()));
        self.responses = Arc::new(Mutex::new(current));
        self
    }

    /// Add a tool call response to the queue.
    ///
    /// Note: This method may not work correctly when the provider is already
    /// shared. Consider creating responses manually for complex scenarios.
    pub fn and_then_tool_call(
        mut self,
        tool_name: impl Into<String>,
        parameters: serde_json::Value,
    ) -> Self {
        let responses_arc = self.responses.clone();
        let mut current = match responses_arc.try_lock() {
            Ok(guard) => guard.clone(),
            Err(_) => return self,
        };

        current.push(MockResponse::success("").with_tool_call(tool_name, parameters));
        self.responses = Arc::new(Mutex::new(current));
        self
    }

    /// Add an error response to the queue.
    ///
    /// Note: This method may not work correctly when the provider is already
    /// shared. Consider creating responses manually for complex scenarios.
    pub fn and_then_error(mut self, error_message: impl Into<String>) -> Self {
        let responses_arc = self.responses.clone();
        let mut current = match responses_arc.try_lock() {
            Ok(guard) => guard.clone(),
            Err(_) => return self,
        };

        current.push(MockResponse::error(error_message));
        self.responses = Arc::new(Mutex::new(current));
        self
    }

    /// Simulate errors after N calls.
    pub fn with_error_after(mut self, count: usize, error_message: impl Into<String>) -> Self {
        self.simulate_error_after = Some((count, error_message.into()));
        self
    }

    /// Set the response delay.
    pub fn with_delay(mut self, delay_ms: u64) -> Self {
        self.response_delay_ms = delay_ms;
        self
    }

    /// Set the model name.
    pub fn with_model(mut self, model: impl Into<String>) -> Self {
        self.model = model.into();
        self
    }

    /// Get the recorded calls.
    pub async fn get_calls(&self) -> Vec<MockCall> {
        self.calls.lock().await.clone()
    }

    /// Get the number of calls made.
    pub async fn call_count(&self) -> usize {
        self.calls.lock().await.len()
    }

    /// Clear the call history.
    pub async fn clear_calls(&self) {
        self.calls.lock().await.clear();
    }

    /// Check if a specific prompt was called.
    pub async fn was_called_with(&self, prompt: &str) -> bool {
        let calls = self.calls.lock().await;
        calls.iter().any(|c| c.prompt.contains(prompt))
    }
}

impl Default for MockProvider {
    fn default() -> Self {
        Self::new()
    }
}

#[async_trait]
impl ChatProvider for MockProvider {
    async fn process(
        &self,
        prompt: &str,
        _context: &DashboardContext,
        tools: &[ProviderTool],
    ) -> Result<ProviderResponse> {
        // Record the call
        let call = MockCall {
            prompt: prompt.to_string(),
            tools_available: tools.len(),
            timestamp: Utc::now(),
        };
        self.calls.lock().await.push(call);

        // Check if we should simulate an error
        if let Some((count, ref error_msg)) = self.simulate_error_after {
            let current_count = self.calls.lock().await.len();
            if current_count > count {
                return Err(ChatError::ApiError(error_msg.clone()));
            }
        }

        // Simulate delay
        if self.response_delay_ms > 0 {
            tokio::time::sleep(Duration::from_millis(self.response_delay_ms)).await;
        }

        // Get the next response
        let mut responses = self.responses.lock().await;
        let response = if responses.is_empty() {
            // If no responses queued, return a default
            MockResponse::success("Mock response")
        } else if responses.len() == 1 {
            // If only one response, reuse it (for single-response providers)
            responses[0].clone()
        } else {
            // If multiple responses, consume one and return it
            responses.remove(0)
        };

        // Check if this is an error response
        if response.is_error {
            return Err(ChatError::ApiError(
                response
                    .error_message
                    .unwrap_or_else(|| "Mock error".to_string()),
            ));
        }

        Ok(ProviderResponse {
            text: response.text,
            tool_calls: response.tool_calls,
            duration_ms: self.response_delay_ms,
            cost_usd: Some(0.0),
            finish_reason: FinishReason::Stop,
            usage: None,
        })
    }

    fn name(&self) -> &str {
        "mock"
    }

    fn estimated_cost(&self) -> Option<f64> {
        Some(0.0)
    }

    fn model(&self) -> &str {
        &self.model
    }
}

// ============ Opencode CLI Provider ============

/// Opencode CLI provider using subprocess communication.
///
/// This provider spawns an opencode process with `--format json` and parses
/// the streaming JSON output events.
///
/// # Output Format
///
/// Opencode outputs JSON lines with the following event types:
/// - `step_start`: Indicates a new step is starting
/// - `text`: Contains actual text output in `part.text`
/// - `step_finish`: Indicates step completion with token usage
pub struct OpencodeProvider {
    config: OpencodeConfig,
}

impl OpencodeProvider {
    /// Create a new Opencode provider.
    pub fn new(config: OpencodeConfig) -> Self {
        Self { config }
    }

    /// Create a provider from a ChatConfig.
    pub fn from_chat_config(_config: &ChatConfig) -> Self {
        Self::new(OpencodeConfig::default())
    }

    /// Send a request to opencode and parse the streaming JSON response.
    async fn send_request(&self, prompt: &str) -> Result<OpencodeResponse> {
        let mut cmd = Command::new(&self.config.binary_path);

        // Build command: opencode run --format json --model <model> "<prompt>"
        cmd.args(["run", "--format", "json", "--model", &self.config.model])
            .arg(prompt);

        // Set up pipes
        cmd.stdin(Stdio::null())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped());

        info!("Spawning opencode: {:?}", cmd);

        let mut child = cmd
            .spawn()
            .map_err(|e| ChatError::ConfigError(format!("Failed to spawn opencode: {}", e)))?;

        let stdout = child.stdout.take().ok_or_else(|| {
            ChatError::ConfigError("Failed to open stdout for opencode".to_string())
        })?;

        let stderr = child.stderr.take().ok_or_else(|| {
            ChatError::ConfigError("Failed to open stderr for opencode".to_string())
        })?;

        // Read stdout with timeout
        let stdout_bytes = timeout(Duration::from_secs(self.config.timeout_secs), async {
            use tokio::io::AsyncReadExt;
            let mut buf = vec![];
            let mut stdout = stdout;
            stdout.read_to_end(&mut buf).await?;
            Ok::<Vec<u8>, std::io::Error>(buf)
        })
        .await
        .map_err(|_| {
            let _ = child.kill();
            ChatError::ApiError("opencode timeout".to_string())
        })?
        .map_err(ChatError::IoError)?;

        // Read stderr for debugging
        let stderr_bytes = timeout(Duration::from_secs(1), async {
            use tokio::io::AsyncReadExt;
            let mut buf = vec![];
            let mut stderr = stderr;
            stderr.read_to_end(&mut buf).await?;
            Ok::<Vec<u8>, std::io::Error>(buf)
        })
        .await
        .unwrap_or(Ok(vec![]))
        .unwrap_or_default();

        // Wait for process to exit
        let status = timeout(Duration::from_secs(5), child.wait())
            .await
            .map_err(|_| ChatError::ApiError("opencode hang on exit".to_string()))??;

        if !status.success() {
            let stderr_str = String::from_utf8_lossy(&stderr_bytes);
            return Err(ChatError::ApiError(format!(
                "opencode exited with status: {:?}, stderr: {}",
                status, stderr_str
            )));
        }

        // Parse the streaming JSON response
        let stdout_str = String::from_utf8(stdout_bytes)
            .map_err(|e| ChatError::ApiError(format!("Invalid UTF-8 from opencode: {}", e)))?;

        debug!("opencode raw output: {}", stdout_str);

        self.parse_opencode_response(&stdout_str)
    }

    /// Parse opencode streaming JSON response.
    ///
    /// The response consists of JSON lines with events:
    /// - {"type":"step_start",...}
    /// - {"type":"text","part":{"text":"Hello there"},...}
    /// - {"type":"step_finish","part":{"tokens":{...},"cost":0},...}
    fn parse_opencode_response(&self, output: &str) -> Result<OpencodeResponse> {
        let mut text_parts = Vec::new();
        let mut total_cost = 0.0;
        let mut usage = TokenUsage::zero();

        for line in output.lines() {
            let line = line.trim();
            if line.is_empty() {
                continue;
            }

            // Parse each JSON line
            let event: OpencodeEvent = match serde_json::from_str(line) {
                Ok(e) => e,
                Err(e) => {
                    debug!("Failed to parse opencode line as event: {} - {}", line, e);
                    continue;
                }
            };

            match event.event_type.as_str() {
                "text" => {
                    // Extract text from the part.text field
                    if let Some(part) = event.part {
                        if let Some(text) = part.text {
                            // Skip synthetic messages (like "Continue if you have next steps")
                            if part.synthetic != Some(true) {
                                text_parts.push(text);
                            }
                        }
                    }
                }
                "step_finish" => {
                    // Extract cost and token usage
                    if let Some(part) = event.part {
                        if let Some(cost) = part.cost {
                            total_cost += cost;
                        }
                        if let Some(tokens) = part.tokens {
                            usage.input_tokens = tokens.input.unwrap_or(0) as u32;
                            usage.output_tokens = tokens.output.unwrap_or(0) as u32;
                        }
                    }
                }
                _ => {
                    // Ignore step_start and other events
                }
            }
        }

        // Combine all text parts
        let full_text = text_parts.join("\n");

        Ok(OpencodeResponse {
            text: full_text,
            cost: total_cost,
            usage,
        })
    }
}

/// Response from opencode CLI.
struct OpencodeResponse {
    text: String,
    cost: f64,
    usage: TokenUsage,
}

/// Opencode streaming event types.
#[derive(Debug, Deserialize)]
struct OpencodeEvent {
    #[serde(rename = "type")]
    event_type: String,
    part: Option<OpencodePart>,
