    #[serde(default)]
    synthetic: Option<bool>,
    cost: Option<f64>,
    tokens: Option<OpencodeTokens>,
}

/// Token usage from opencode.
#[derive(Debug, Deserialize)]
struct OpencodeTokens {
    input: Option<u64>,
    output: Option<u64>,
}

